import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as o,a}from"./app-e1a47c85.js";const i={},l=a('<h1 id="matematika" tabindex="-1"><a class="header-anchor" href="#matematika" aria-hidden="true">#</a> Matematika</h1><div class="hint-container note"><p class="hint-container-title">Röviden</p><ul><li>Az összeadás (<code>+</code>), kivonás (<code>-</code>), szorzás (<code>*</code>), osztás (<code>/</code>) és maradék (<code>%</code>) mind használható matematikai kifejezésekhez: <code>int a = 3 + 2 / 4 * 6;</code></li><li>A <code>+</code> és <code>-</code> operátorok előjelek jelölésére (<em>vagy egy érték negálására</em>) is használhatók: <em>+3</em>, <em>-2</em> vagy <em>-a</em>.</li><li>A műveletek sorrendje megfelel a matematikai világnak.</li><li>A sorrendet úgy változtathatja meg, hogy zárójelek segítségével csoportosítja azokat a dolgokat, amelyeket először szeretne elvégezni.</li><li>Az összetett hozzárendelési operátorok (<code>+=</code>, <code>-=</code>, <code>*=</code>, <code>/=</code>, <code>%=</code>) olyan rövidítések, amelyek egy változót egy matematikai művelettel állítanak be. <code>a += 3;</code> ugyanaz, mint <code>a = a + 3;</code></li><li>A növelő és csökkentő operátorok: <code>a++;</code> <code>b--;</code></li><li>A numerikus típusok mindegyike definiál speciális értékeket a tartományaikhoz (<code>int.MaxValue</code>, <code>double.MinValue</code>, stb.), a lebegőpontos típusok pedig <code>PositiveInfinity</code>, <code>NegativeInfinity</code> és <code>NaN</code> értékeket is definiálnak.</li><li>Az egész számok osztása elhagyja a maradékokat, míg a lebegőpontos osztás nem.</li><li>A típusok között átváltással konvertálhatunk: <code>int x = (int)3.3;</code></li><li>A <code>Math</code> és <code>MathF</code> osztályok tartalmaznak egy sor segédmetódust a gyakori matematikai műveletek kezelésére.</li></ul></div><p>A számítógépeket a matematika céljából építették fel, és itt az ideje, hogy megnézzük, hogyan lehet a számítógépet néhány alapvető számításra felhasználni.</p><h2 id="muveletek-es-operatorok" tabindex="-1"><a class="header-anchor" href="#muveletek-es-operatorok" aria-hidden="true">#</a> Műveletek és operátorok</h2>',4),s=[l];function d(c,n){return t(),o("div",null,s)}const m=e(i,[["render",d],["__file","lesson7.html.vue"]]);export{m as default};
